import { Component, OnInit, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { HttpClient } from '@angular/common/http';
import { environment } from '../../../environments/environment';
import { Profile } from '../../core/models';
import { ToastService } from '../../core/services/toast.service';

@Component({
  selector: 'app-profile-edit',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './profile-edit.component.html',
  styleUrl: './profile-edit.component.css',
})
export class ProfileEditComponent implements OnInit {
  private toast = inject(ToastService);
  private http = inject(HttpClient);
  private readonly apiUrl = environment.apiUrl;

  // Editable form fields, hydrated from GET {apiUrl}/profile in ngOnInit().
  readonly name = signal('');
  readonly jobTitle = signal('');
  readonly employer = signal('');
  readonly bio = signal('');
  readonly photos = signal<string[]>([]);
  readonly saved = signal(false);

  readonly maxBio = 500;
  readonly bioCount = computed(() => this.bio().length);
  readonly hasPhoto = computed(() => this.photos().length > 0);
  readonly hasBio = computed(() => this.bio().trim().length > 0);
  readonly complete = computed(() => this.hasPhoto() && this.hasBio());

  ngOnInit(): void {
    this.http.get<Profile>(`${this.apiUrl}/profile`).subscribe({
      next: (p) => this.hydrate(p),
      error: () => {},
    });
  }

  private hydrate(p: Profile): void {
    if (!p) return;
    this.name.set(p.name ?? '');
    this.jobTitle.set(p.jobTitle ?? '');
    this.employer.set(p.employer ?? '');
    this.bio.set(p.bio ?? '');
    this.photos.set([...(p.photos ?? [])]);
  }

  addPhoto(): void {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = () => {
      const file = input.files?.[0];
      if (file) this.uploadPhoto(file);
    };
    input.click();
  }

  private uploadPhoto(file: File): void {
    const form = new FormData();
    form.append('photo', file);
    this.http.post<{ photos?: string[]; url?: string }>(`${this.apiUrl}/profile/photos`, form).subscribe({
      next: (res) => {
        if (res?.photos) {
          this.photos.set([...res.photos]);
        } else if (res?.url) {
          this.photos.update((p) => [...p, res.url!]);
        }
      },
      error: () => {},
    });
  }

  removePhoto(url: string): void {
    this.photos.update((p) => p.filter((x) => x !== url));
  }

  save(): void {
    this.http
      .put(`${this.apiUrl}/profile`, {
        name: this.name(),
        jobTitle: this.jobTitle(),
        employer: this.employer(),
        bio: this.bio(),
      })
      .subscribe({
        next: () => {
          this.saved.set(true);
          this.toast.push('message', 'Profile saved', 'Your changes are now visible to other members.');
          setTimeout(() => this.saved.set(false), 1600);
        },
        error: () => {},
      });
  }
}
